List<QuizQuestion> getQuestions(
  String category, {
  int count = 25,
  Set<String> askedQuestions = const {},
}) {
  List<QuizQuestion> pool;

  switch (category) {
    case 'Science':
      pool = List.from(_scienceQuestions);
    case 'Geography':
      pool = List.from(_geographyQuestions);
    case 'Universal Facts':
      pool = List.from(_universalFactsQuestions);
    case 'Friends TV Series':
      pool = List.from(_friendsQuestions);
    case 'Cricket':
      pool = List.from(_cricketQuestions);
    case 'Countries & Capitals':
      pool = List.from(_capitalsQuestions);
    case 'Telugu Movies':
      pool = List.from(_teluguMoviesQuestions);
    case 'Know India':
      pool = List.from(_knowIndiaQuestions);
    case 'Random':
      pool = [
        ..._scienceQuestions,
        ..._geographyQuestions,
        ..._universalFactsQuestions,
        ..._friendsQuestions,
        ..._cricketQuestions,
        ..._capitalsQuestions,
        ..._teluguMoviesQuestions,
        ..._knowIndiaQuestions,
      ];
    default:
      pool = List.from(_scienceQuestions);
  }

  // Filter out previously asked questions if any
  if (askedQuestions.isNotEmpty) {
    final fresh = pool.where((q) => !askedQuestions.contains(q.question)).toList();
    // If we have enough fresh questions, use only those
    if (fresh.length >= count) {
      pool = fresh;
    }
    // Otherwise fall back to full pool (allows repeats when exhausted)
  }

  pool.shuffle();
  return pool.take(count).toList();
}
